<script>import'../../../../public/native-control.css';let cases=[{"label":"Airplane mode"},{"label":"Notifications","checked":true},{"label":"Disabled","disabled":true},{"label":"Compact","compact":true}];</script><main class="native-shell"><h1>Switch</h1><section class="native-matrix">{#each cases as p}<label class="native-control switch" class:compact={p.compact}><input type="checkbox" role="switch" bind:checked={p.checked} disabled={p.disabled} required={p.required}/><span class="indicator" aria-hidden="true"></span><span>{p.label}</span></label>{/each}</section></main>